import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  ShoppingBag, 
  Package, 
  BarChart3, 
  Settings, 
  Users, 
  ChevronRight, 
  Trash2, 
  Plus, 
  Minus, 
  Receipt as ReceiptIcon,
  CreditCard,
  Banknote,
  LogOut,
  Sparkles,
  Info
} from 'lucide-react';
import { 
  Category, 
  Product, 
  CartItem, 
  Sale, 
  PaymentMethod, 
  UserRole, 
  Operator, 
  CashSession,
  VatRate,
  Unit
} from './types';
import { INITIAL_PRODUCTS, OPERATORS } from './constants';
import { Receipt } from './components/Receipt';
import { GeminiService } from './services/geminiService';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';

// --- Components ---

const SidebarItem: React.FC<{ 
  icon: React.ReactNode; 
  label: string; 
  active: boolean; 
  onClick: () => void;
}> = ({ icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
      active 
        ? 'bg-amber-600 text-white shadow-md' 
        : 'text-stone-500 hover:bg-stone-100'
    }`}
  >
    {icon}
    <span className="font-medium">{label}</span>
  </button>
);

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState<'pos' | 'inventory' | 'reports' | 'operators'>('pos');
  const [currentOperator, setCurrentOperator] = useState<Operator | null>(null);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [session, setSession] = useState<CashSession | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<Category | 'Tutti'>('Tutti');
  const [checkoutModal, setCheckoutModal] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Derived State
  const totals = useMemo(() => {
    const subtotal = cart.reduce((acc, item) => {
      const price = item.basePrice + (item.variantSelections?.size?.priceDelta || 0);
      return acc + (price * item.quantity);
    }, 0);

    const vatTotal = cart.reduce((acc, item) => {
      const price = item.basePrice + (item.variantSelections?.size?.priceDelta || 0);
      const totalForItem = price * item.quantity;
      const vatAmount = totalForItem - (totalForItem / (1 + item.vatRate / 100));
      return acc + vatAmount;
    }, 0);

    return { total: subtotal, vatTotal, subtotal: subtotal - vatTotal };
  }, [cart]);

  // Methods
  const handleAddToCart = (product: Product) => {
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      setCart(cart.map(item => 
        item.productId === product.id 
          ? { ...item, quantity: item.quantity + (product.unit === Unit.KG ? 0.1 : 1) }
          : item
      ));
    } else {
      setCart([...cart, {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        name: product.name,
        basePrice: product.price,
        quantity: product.unit === Unit.KG ? 0.1 : 1,
        vatRate: product.vatRate,
      }]);
    }
  };

  const removeFromCart = (itemId: string) => {
    setCart(cart.filter(item => item.id !== itemId));
  };

  const updateQuantity = (itemId: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === itemId) {
        const newQty = Math.max(0.1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = (method: PaymentMethod) => {
    const newSale: Sale = {
      id: `SALE-${Date.now()}`,
      items: [...cart],
      total: totals.total,
      vatTotal: totals.vatTotal,
      subtotal: totals.subtotal,
      paymentMethod: method,
      timestamp: new Date(),
      operator: currentOperator?.name || 'Sistema',
      receiptNumber: sales.length + 1
    };

    setSales([newSale, ...sales]);

    // Update Stock
    setProducts(products.map(p => {
      const soldItem = cart.find(ci => ci.productId === p.id);
      if (soldItem) {
        return { ...p, stock: Math.max(0, p.stock - soldItem.quantity) };
      }
      return p;
    }));

    setCart([]);
    setCheckoutModal(false);
    alert('Vendita completata!');
  };

  const askGemini = async () => {
    setLoadingAi(true);
    const gemini = new GeminiService();
    const insights = await gemini.analyzeSales(sales.slice(0, 10));
    setAiInsight(insights || "Nessun dato sufficiente per l'analisi.");
    setLoadingAi(false);
  };

  // Auth Guard (Simulated)
  if (!currentOperator) {
    return (
      <div className="min-h-screen bg-stone-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-md text-center">
          <div className="w-20 h-20 bg-amber-100 rounded-2xl flex items-center justify-center mx-auto mb-6 text-amber-600">
            <ShoppingBag size={40} />
          </div>
          <h1 className="text-2xl font-bold mb-2">Panetteria Pro</h1>
          <p className="text-stone-500 mb-8">Effettua il login per iniziare il turno</p>
          <div className="space-y-4">
            {OPERATORS.map(op => (
              <button
                key={op.id}
                onClick={() => setCurrentOperator(op)}
                className="w-full py-4 px-6 border-2 border-stone-100 rounded-2xl hover:border-amber-500 hover:bg-amber-50 transition-all flex items-center justify-between"
              >
                <div className="flex flex-col items-start">
                  <span className="font-bold">{op.name}</span>
                  <span className="text-xs text-stone-400">{op.role}</span>
                </div>
                <ChevronRight className="text-stone-300" />
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-stone-200 flex flex-col no-print">
        <div className="p-6">
          <div className="flex items-center space-x-3 mb-8">
            <div className="bg-amber-600 p-2 rounded-lg text-white">
              <ShoppingBag size={24} />
            </div>
            <span className="font-bold text-xl tracking-tight">Panetteria</span>
          </div>

          <nav className="space-y-2">
            <SidebarItem 
              icon={<ShoppingBag size={20} />} 
              label="Vendita" 
              active={activeTab === 'pos'} 
              onClick={() => setActiveTab('pos')} 
            />
            <SidebarItem 
              icon={<Package size={20} />} 
              label="Magazzino" 
              active={activeTab === 'inventory'} 
              onClick={() => setActiveTab('inventory')} 
            />
            <SidebarItem 
              icon={<BarChart3 size={20} />} 
              label="Report" 
              active={activeTab === 'reports'} 
              onClick={() => setActiveTab('reports')} 
            />
            <SidebarItem 
              icon={<Users size={20} />} 
              label="Operatori" 
              active={activeTab === 'operators'} 
              onClick={() => setActiveTab('operators')} 
            />
          </nav>
        </div>

        <div className="mt-auto p-6 border-t border-stone-100">
          <div className="flex items-center space-x-3 mb-4">
            <div className="w-10 h-10 rounded-full bg-stone-100 flex items-center justify-center font-bold text-stone-600">
              {currentOperator.name.charAt(0)}
            </div>
            <div className="flex flex-col">
              <span className="font-medium text-sm">{currentOperator.name}</span>
              <span className="text-xs text-stone-400">{currentOperator.role}</span>
            </div>
          </div>
          <button 
            onClick={() => setCurrentOperator(null)}
            className="w-full flex items-center justify-center space-x-2 py-2 px-4 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
          >
            <LogOut size={16} />
            <span className="text-sm font-medium">Chiudi Turno</span>
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col bg-stone-50 overflow-hidden no-print">
        {/* Top Header */}
        <header className="bg-white border-b border-stone-200 px-8 py-4 flex justify-between items-center">
          <h2 className="text-xl font-bold text-stone-800">
            {activeTab === 'pos' && 'Cassa Registratrice'}
            {activeTab === 'inventory' && 'Gestione Prodotti'}
            {activeTab === 'reports' && 'Analisi Vendite'}
            {activeTab === 'operators' && 'Gestione Personale'}
          </h2>
          <div className="flex items-center space-x-4">
            <div className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-bold flex items-center space-x-1">
              <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
              <span>CASSA APERTA</span>
            </div>
            <span className="text-sm text-stone-500">{new Date().toLocaleDateString('it-IT')}</span>
          </div>
        </header>

        {/* Dynamic Content */}
        <div className="flex-1 overflow-auto p-8">

          {/* POS TAB */}
          {activeTab === 'pos' && (
            <div className="flex h-full space-x-8">
              {/* Product Area */}
              <div className="flex-1 flex flex-col space-y-6">
                {/* Categories */}
                <div className="flex space-x-2 overflow-x-auto pb-2 scrollbar-hide">
                  {['Tutti', ...Object.values(Category)].map(cat => (
                    <button
                      key={cat}
                      onClick={() => setSelectedCategory(cat as any)}
                      className={`px-5 py-2 rounded-full whitespace-nowrap text-sm font-medium transition-all ${
                        selectedCategory === cat 
                          ? 'bg-stone-800 text-white shadow-lg' 
                          : 'bg-white text-stone-600 hover:bg-stone-100'
                      }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>

                {/* Grid */}
                <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                  {products
                    .filter(p => selectedCategory === 'Tutti' || p.category === selectedCategory)
                    .map(product => (
                      <button
                        key={product.id}
                        onClick={() => handleAddToCart(product)}
                        disabled={product.stock <= 0}
                        className={`bg-white p-4 rounded-2xl shadow-sm border border-stone-200 hover:shadow-md hover:border-amber-300 transition-all text-left flex flex-col h-40 ${
                          product.stock <= 0 ? 'opacity-50 grayscale cursor-not-allowed' : ''
                        }`}
                      >
                        <span className="text-xs font-bold text-amber-600 uppercase mb-1">{product.category}</span>
                        <h3 className="font-bold text-stone-800 mb-auto leading-tight line-clamp-2">{product.name}</h3>
                        <div className="flex justify-between items-end mt-4">
                          <span className="text-lg font-black">€{product.price.toFixed(2)}</span>
                          <span className={`text-[10px] px-2 py-0.5 rounded-full ${
                            product.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-stone-100 text-stone-400'
                          }`}>
                            Qta: {product.stock.toFixed(1)}{product.unit}
                          </span>
                        </div>
                      </button>
                    ))}
                </div>
              </div>

              {/* Cart Sidebar */}
              <div className="w-96 bg-white rounded-3xl shadow-xl border border-stone-200 flex flex-col">
                <div className="p-6 border-b border-stone-100 flex justify-between items-center">
                  <h3 className="font-bold text-lg">Ordine Corrente</h3>
                  <span className="text-xs bg-stone-100 px-2 py-1 rounded text-stone-500 font-mono">#{sales.length + 1}</span>
                </div>

                <div className="flex-1 overflow-auto p-4 space-y-3">
                  {cart.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-stone-300 space-y-4">
                      <ShoppingBag size={64} strokeWidth={1} />
                      <p className="font-medium">Il carrello è vuoto</p>
                    </div>
                  ) : (
                    cart.map(item => (
                      <div key={item.id} className="bg-stone-50 p-3 rounded-xl border border-stone-100">
                        <div className="flex justify-between items-start mb-2">
                          <h4 className="font-bold text-sm text-stone-800 line-clamp-1">{item.name}</h4>
                          <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600">
                            <Trash2 size={16} />
                          </button>
                        </div>
                        <div className="flex items-center justify-between">
                          <div className="flex items-center space-x-2 bg-white rounded-lg border border-stone-200 p-1">
                            <button onClick={() => updateQuantity(item.id, -0.1)} className="p-1 hover:bg-stone-50 rounded"><Minus size={14}/></button>
                            <span className="text-sm font-bold w-12 text-center">{item.quantity.toFixed(1)}</span>
                            <button onClick={() => updateQuantity(item.id, 0.1)} className="p-1 hover:bg-stone-50 rounded"><Plus size={14}/></button>
                          </div>
                          <span className="font-bold text-stone-800">€{(item.basePrice * item.quantity).toFixed(2)}</span>
                        </div>
                      </div>
                    ))
                  )}
                </div>

                <div className="p-6 bg-stone-50 rounded-b-3xl border-t border-stone-200">
                  <div className="space-y-2 mb-6 text-sm">
                    <div className="flex justify-between text-stone-500">
                      <span>Subtotale (Imponibile)</span>
                      <span>€{totals.subtotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-stone-500">
                      <span>IVA Totale</span>
                      <span>€{totals.vatTotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between font-black text-xl text-stone-900 pt-2 border-t border-stone-200">
                      <span>TOTALE</span>
                      <span>€{totals.total.toFixed(2)}</span>
