  const [checkoutModal, setCheckoutModal] = useState(false);
  const [amountPaid, setAmountPaid] = useState<string>('');
  const [selectedPaymentMethod, setSelectedPaymentMethod] = useState<PaymentMethod | null>(null);
  const [lastCompletedSale, setLastCompletedSale] = useState<Sale | null>(null);

  // AI & Reports State
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Closure State
  const [realCashInput, setRealCashInput] = useState<string>('');
  const [startingCash, setStartingCash] = useState<number>(100);

  // Derived State (Cart Totals & VAT Breakdown)
  const totals = useMemo(() => {
    const breakdown: Record<number, { taxable: number; vat: number }> = {};

    const subtotal = cart.reduce((acc, item) => {
      const price = item.basePrice + (item.variantSelections?.size?.priceDelta || 0);
      const totalForItem = price * item.quantity;
      const vatRate = item.vatRate;

      const taxable = totalForItem / (1 + vatRate / 100);
      const vat = totalForItem - taxable;

      if (!breakdown[vatRate]) breakdown[vatRate] = { taxable: 0, vat: 0 };
      breakdown[vatRate].taxable += taxable;
      breakdown[vatRate].vat += vat;

      return acc + totalForItem;
    }, 0);

    const vatTotal = Object.values(breakdown).reduce((sum, b) => sum + b.vat, 0);

    const vatBreakdownList: VatBreakdown[] = Object.entries(breakdown).map(([rate, vals]) => ({
      rate: Number(rate),
      taxable: vals.taxable,
      vatAmount: vals.vat
    }));

    return { total: subtotal, vatTotal, subtotal: subtotal - vatTotal, vatBreakdown: vatBreakdownList };
  }, [cart]);

  // Methods
  const handleAddToCart = (product: Product) => {
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      setCart(cart.map(item => 
        item.productId === product.id 
          ? { ...item, quantity: item.quantity + (product.unit === Unit.KG ? 0.1 : 1) }
          : item
      ));
    } else {
      setCart([...cart, {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        name: product.name,
        basePrice: product.price,
        quantity: product.unit === Unit.KG ? 0.1 : 1,
        vatRate: product.vatRate,
      }]);
    }
  };

  const updateQuantity = (itemId: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === itemId) {
        const newQty = Math.max(0.1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = () => {
    if (!selectedPaymentMethod) return;

    const paid = parseFloat(amountPaid) || totals.total;
    const change = Math.max(0, paid - totals.total);

    const newSale: Sale = {
      id: `SALE-${Date.now()}`,
      items: [...cart],
      total: totals.total,
      vatTotal: totals.vatTotal,
      subtotal: totals.subtotal,
      paymentMethod: selectedPaymentMethod,
      timestamp: new Date(),
      operator: currentOperator?.name || 'Sistema',
      receiptNumber: sales.length + 1,
      amountPaid: paid,
      changeGiven: change,
      vatBreakdown: totals.vatBreakdown
    };

    setSales([newSale, ...sales]);

    // Update Stock
    setProducts(prev => prev.map(p => {
      const soldItem = cart.find(ci => ci.productId === p.id);
      if (soldItem) return { ...p, stock: Math.max(0, p.stock - soldItem.quantity) };
      return p;
    }));

    setCart([]);
    setCheckoutModal(false);
    setSelectedPaymentMethod(null);
    setAmountPaid('');
    setLastCompletedSale(newSale); // Trigger receipt modal
  };

  const askGemini = async () => {
    setLoadingAi(true);
    const gemini = new GeminiService();
    const insights = await gemini.analyzeSales(sales.slice(0, 10));
    setAiInsight(insights || "Nessun dato sufficiente per l'analisi.");
    setLoadingAi(false);
  };

  // Stats Calcs
  const dailyStats = useMemo(() => {
    const revenue = sales.reduce((acc, s) => acc + s.total, 0);
    const avgTicket = sales.length > 0 ? revenue / sales.length : 0;
    const itemsCount = sales.reduce((acc, s) => acc + s.items.reduce((sum, i) => sum + i.quantity, 0), 0);

    const catSales: Record<string, number> = {};
    sales.forEach(s => {
      s.items.forEach(item => {
        const p = products.find(prod => prod.id === item.productId);
        const cat = p?.category || 'Altro';
        catSales[cat] = (catSales[cat] || 0) + (item.basePrice * item.quantity);
      });
    });

    const hourlySales: Record<number, number> = {};
    sales.forEach(s => {
      const hour = new Date(s.timestamp).getHours();
      hourlySales[hour] = (hourlySales[hour] || 0) + s.total;
    });

    return { revenue, avgTicket, itemsCount, catSales, hourlySales };
  }, [sales, products]);

  // Auth Guard
  if (!currentOperator) {
    return (
      <div className="min-h-screen bg-stone-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-md text-center">
          <div className="w-20 h-20 bg-amber-100 rounded-2xl flex items-center justify-center mx-auto mb-6 text-amber-600">
            <ShoppingBag size={40} />
          </div>
          <h1 className="text-2xl font-bold mb-2">Panetteria Pro</h1>
          <p className="text-stone-500 mb-8">Login Operatore</p>
          <div className="space-y-4">
            {OPERATORS.map(op => (
              <button
                key={op.id}
                onClick={() => setCurrentOperator(op)}
                className="w-full py-4 px-6 border-2 border-stone-100 rounded-2xl hover:border-amber-500 hover:bg-amber-50 transition-all flex items-center justify-between"
              >
                <div className="flex flex-col items-start">
                  <span className="font-bold">{op.name}</span>
                  <span className="text-xs text-stone-400 uppercase tracking-widest">{op.role}</span>
                </div>
                <ChevronRight className="text-stone-300" />
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-stone-200 flex flex-col no-print">
        <div className="p-6">
          <div className="flex items-center space-x-3 mb-8">
            <div className="bg-amber-600 p-2 rounded-lg text-white">
              <ShoppingBag size={24} />
            </div>
            <span className="font-bold text-xl tracking-tight text-stone-800">Panetteria</span>
          </div>

          <nav className="space-y-2">
            <SidebarItem icon={<ShoppingBag size={20} />} label="Vendita" active={activeTab === 'pos'} onClick={() => setActiveTab('pos')} />
            <SidebarItem icon={<Package size={20} />} label="Magazzino" active={activeTab === 'inventory'} onClick={() => setActiveTab('inventory')} />
            <SidebarItem icon={<BarChart3 size={20} />} label="Report & Statistiche" active={activeTab === 'reports'} onClick={() => setActiveTab('reports')} />
            <SidebarItem icon={<SettingsIcon size={20} />} label="Impostazioni" active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} />
            <SidebarItem icon={<Users size={20} />} label="Personale" active={activeTab === 'operators'} onClick={() => setActiveTab('operators')} />
            <div className="pt-4 mt-4 border-t border-stone-100">
              <SidebarItem icon={<History size={20} />} label="Chiusura Cassa" active={activeTab === 'closure'} onClick={() => setActiveTab('closure')} />
            </div>
          </nav>
        </div>

        <div className="mt-auto p-6 border-t border-stone-100">
          <div className="flex items-center space-x-3 mb-4">
            <div className="w-10 h-10 rounded-full bg-stone-100 flex items-center justify-center font-bold text-stone-600 border border-stone-200">
              {currentOperator.name.charAt(0)}
            </div>
            <div className="flex flex-col">
              <span className="font-medium text-sm text-stone-700">{currentOperator.name}</span>
              <span className="text-[10px] text-stone-400 font-bold uppercase tracking-tighter">{currentOperator.role}</span>
            </div>
          </div>
          <button 
            onClick={() => setCurrentOperator(null)}
            className="w-full flex items-center justify-center space-x-2 py-2.5 px-4 text-red-500 hover:bg-red-50 rounded-xl transition-all border border-transparent hover:border-red-100 font-bold text-sm"
          >
            <LogOut size={16} />
            <span>Fine Turno</span>
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col bg-stone-50 overflow-hidden no-print">
