          <h2 className="text-xl font-bold text-stone-800">
            {activeTab === 'pos' && 'Terminale di Vendita'}
            {activeTab === 'inventory' && 'Inventario'}
            {activeTab === 'reports' && 'Analisi Business'}
            {activeTab === 'settings' && 'Pannello di Controllo'}
            {activeTab === 'operators' && 'Gestione Personale'}
