                        <div className="flex items-center justify-between">
                          <div className="flex items-center space-x-2 bg-stone-50 rounded-xl p-1.5 border border-stone-100">
                            <button onClick={() => updateQuantity(item.id, -0.1)} className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"><Minus size={14}/></button>
                            <span className="text-xs font-black w-10 text-center">{item.quantity.toFixed(1)}</span>
                            <button onClick={() => updateQuantity(item.id, 0.1)} className="p-1 hover:bg-white hover:shadow-sm rounded-lg transition-all"><Plus size={14}/></button>
                          </div>
                          <span className="font-black text-stone-900">€{(item.basePrice * item.quantity).toFixed(2)}</span>
                        </div>
                      </div>
                    ))
                  )}
                </div>

                <div className="p-7 bg-stone-50 border-t border-stone-100">
                  <div className="space-y-2 mb-6 text-sm">
                    <div className="flex justify-between text-stone-400 font-medium">
                      <span>Imponibile</span>
                      <span>€{totals.subtotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-stone-400 font-medium">
                      <span>IVA</span>
                      <span>€{totals.vatTotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between font-black text-3xl text-stone-900 pt-4 border-t-2 border-stone-200">
                      <span>TOTALE</span>
                      <span>€{totals.total.toFixed(2)}</span>
                    </div>
                  </div>

                  <button
                    disabled={cart.length === 0}
                    onClick={() => { setCheckoutModal(true); setAmountPaid(totals.total.toFixed(2)); }}
                    className="w-full bg-stone-900 text-white py-5 rounded-2xl font-black shadow-2xl hover:bg-amber-600 disabled:opacity-30 disabled:hover:bg-stone-900 transition-all flex items-center justify-center space-x-3 text-lg"
                  >
                    <CreditCard size={24} />
                    <span>CONCLUDI VENDITA</span>
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* REPORTS TAB */}
          {activeTab === 'reports' && (
            <div className="space-y-8 pb-12">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-stone-200">
                  <p className="text-stone-400 text-[10px] font-black uppercase mb-1 tracking-widest">Incasso Lordo</p>
                  <h4 className="text-3xl font-black text-amber-600">€{dailyStats.revenue.toFixed(2)}</h4>
                </div>
                <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-stone-200">
                  <p className="text-stone-400 text-[10px] font-black uppercase mb-1 tracking-widest">Scontrino Medio</p>
                  <h4 className="text-3xl font-black text-stone-800">€{dailyStats.avgTicket.toFixed(2)}</h4>
                </div>
                <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-stone-200">
                  <p className="text-stone-400 text-[10px] font-black uppercase mb-1 tracking-widest">Prodotti Venduti</p>
                  <h4 className="text-3xl font-black text-stone-800">{dailyStats.itemsCount.toFixed(0)}</h4>
                </div>
                <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-stone-200">
                  <p className="text-stone-400 text-[10px] font-black uppercase mb-1 tracking-widest">Performance</p>
                  <h4 className="text-3xl font-black text-green-600">+12%</h4>
                </div>
              </div>

              <div className="bg-indigo-600 rounded-[2.5rem] p-10 text-white relative overflow-hidden shadow-2xl">
                 <div className="relative z-10">
                   <div className="flex items-center space-x-4 mb-6">
                     <div className="bg-white/20 p-2.5 rounded-2xl backdrop-blur-md">
                        <Sparkles className="text-amber-400 fill-amber-400" size={24} />
                     </div>
                     <h3 className="font-black text-2xl tracking-tighter uppercase">Gemini AI Insights</h3>
                   </div>
                   {aiInsight ? (
                     <div className="bg-white/10 backdrop-blur-md p-6 rounded-3xl border border-white/10">
                        <p className="text-indigo-50 leading-relaxed font-medium whitespace-pre-wrap">{aiInsight}</p>
                     </div>
                   ) : (
                     <p className="text-indigo-100 mb-8 font-medium text-lg">Richiedi un'analisi strategica dei dati di vendita per ottimizzare il tuo inventario.</p>
                   )}
                   <button 
                    onClick={askGemini}
                    disabled={loadingAi}
                    className="mt-6 bg-white text-indigo-600 px-10 py-4 rounded-2xl font-black hover:bg-amber-400 hover:text-white transition-all shadow-2xl flex items-center space-x-3 uppercase tracking-tighter disabled:opacity-50"
                   >
                     {loadingAi ? 'Analisi in corso...' : 'GENERA REPORT STRATEGICO'}
                   </button>
                 </div>
                 <div className="absolute top-0 right-0 w-96 h-96 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white p-10 rounded-[2.5rem] border border-stone-200 shadow-sm">
                  <h4 className="font-black text-stone-800 mb-10 uppercase text-xs tracking-[0.2em] flex items-center">
                    <Clock size={18} className="mr-3 text-amber-500" /> Andamento Orario
                  </h4>
                  <div className="h-80">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={Object.entries(dailyStats.hourlySales).map(([h, t]) => ({ h: h + ':00', t }))}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f5f5f5" />
                        <XAxis dataKey="h" fontSize={11} axisLine={false} tickLine={false} tick={{fill: '#a8a29e'}} />
                        <YAxis fontSize={11} axisLine={false} tickLine={false} tick={{fill: '#a8a29e'}} />
                        <Tooltip cursor={{fill: '#fafaf9'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', fontWeight: 'bold' }} />
                        <Bar dataKey="t" fill="#d97706" radius={[8, 8, 0, 0]} barSize={45} />
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-white p-10 rounded-[2.5rem] border border-stone-200 shadow-sm overflow-hidden">
                   <h4 className="font-black text-stone-800 mb-10 uppercase text-xs tracking-[0.2em] flex items-center">
                    <ReceiptIcon size={18} className="mr-3 text-amber-500" /> Ultime Transazioni
                   </h4>
                   <div className="space-y-4">
                     {sales.slice(0, 5).map(sale => (
                       <div key={sale.id} className="flex items-center justify-between p-5 bg-stone-50/50 rounded-3xl border border-stone-100 hover:border-amber-200 hover:bg-white transition-all group">
                         <div className="flex items-center space-x-5">
                           <div className="bg-white p-3.5 rounded-2xl shadow-sm border border-stone-100 group-hover:scale-110 transition-transform">
                             <ReceiptIcon size={22} className="text-stone-400 group-hover:text-amber-500 transition-colors" />
                           </div>
                           <div>
                             <p className="text-base font-black text-stone-900">€{sale.total.toFixed(2)}</p>
                             <p className="text-[10px] text-stone-400 font-bold uppercase tracking-widest mt-0.5">
                               {sale.paymentMethod} • {sale.timestamp.toLocaleTimeString('it-IT')}
                             </p>
                           </div>
                         </div>
                         <button onClick={() => setLastCompletedSale(sale)} className="text-amber-600 text-[10px] font-black uppercase tracking-widest bg-amber-50 px-4 py-2.5 rounded-xl hover:bg-amber-600 hover:text-white transition-all shadow-sm">Scontrino</button>
                       </div>
                     ))}
                   </div>
                </div>
              </div>
            </div>
          )}

          {/* SETTINGS TAB */}
          {activeTab === 'settings' && (
            <div className="space-y-8 max-w-5xl">
