      )}

      {/* SUCCESS MODAL / RECEIPT PREVIEW */}
      {lastCompletedSale && (
        <div className="fixed inset-0 bg-stone-900/90 backdrop-blur-2xl flex items-center justify-center z-[60] p-4 animate-in fade-in duration-300 overflow-auto">
          <div className="flex flex-col items-center space-y-8 w-full max-w-2xl py-12">
